arguments.argument:
if global.gamePaused=false
{
  if bFunctional=1
  {
    spawnTime-=1
    findTargetX=point_distance(oPlayer1.x,0,x,0)
    findTargetY=point_distance(0,oPlayer1.y-26,0,y)
    if findTargetX<=detectDistX and findTargetY<=detectDistY and opening=0
    {
      if spawnTime<=0 and !instance_exists(robotSpawn)
        opening+=1
    }
    
    //Open and spawn enemy
    if opening>=1
    {
      opening+=1
      if opening=2
        image_index=1
      else if opening=8
        image_index=2
      else if opening=14
        image_index=3
      else if opening=30
      {
        robotSpawn=instance_create(x,y,oPincherBot)
        robotSpawn.initDir=pushDir
        spawnTime=240
      }
      else if opening=46
        image_index=2
      else if opening=52
        image_index=1
      else if opening=58
      {
        image_index=0
        opening=0
      }
    }
  }
}
